        impl From<Opt<'_>> for rar_common::database::options::Opt {
            fn from(val: Opt<'_>) -> Self {
                Self::builder(val.level)
                    .maybe_path(
                        if let Some(spath) = val.path {
                            Some(
                                rar_common::database::options::SPathOptions::builder(
                                        spath.default_behavior,
                                    )
                                    .maybe_add(
                                        spath
                                            .add
                                            .map(|v| {
                                                v.iter()
                                                    .map(std::string::ToString::to_string)
                                                    .collect::<Vec<_>>()
                                            }),
                                    )
                                    .maybe_sub(
                                        spath
                                            .sub
                                            .map(|v| {
                                                v.iter()
                                                    .map(std::string::ToString::to_string)
                                                    .collect::<Vec<_>>()
                                            }),
                                    )
                                    .build(),
                            )
                        } else {
                            None
                        },
                    )
                    .maybe_env(
                        if let Some(senv) = val.env {
                            Some(
                                rar_common::database::options::SEnvOptions::builder(
                                        senv.default_behavior,
                                    )
                                    .maybe_override_behavior(senv.override_behavior)
                                    .set(
                                        senv
                                            .set
                                            .into_iter()
                                            .map(|(k, v)| (k.to_string(), v.to_string())),
                                    )
                                    .keep(senv.keep.into_iter().map(|v| v.to_string()))
                                    .unwrap()
                                    .check(senv.check.into_iter().map(|v| v.to_string()))
                                    .unwrap()
                                    .delete(senv.delete.into_iter().map(|v| v.to_string()))
                                    .unwrap()
                                    .build(),
                            )
                        } else {
                            None
                        },
                    )
                    .maybe_root(val.root)
                    .maybe_bounding(val.bounding)
                    .maybe_authentication(val.authentication)
                    .maybe_timeout(val.timeout)
                    .build()
            }
        }
