            term.prompt(&pam_prompt).map_err(|_| ErrorCode::ConversationError)?;
            let read = term.read_password().map_err(|_| ErrorCode::BufferError)?;
            drop(term);
            let os_str = CStr::from_bytes_until_nul(&read)
                .map_err(|_| ErrorCode::BufferError)?
                .to_str()
                .map_err(|_| ErrorCode::BufferError)?;
