const CAPABILITIES_ERROR: &str = "You need at least dac_read_search or dac_override, setpcap and setuid capabilities to run sr";
fn cap_effective_error(caplist: &str) -> String {
    ::alloc::__export::must_use({
        ::alloc::fmt::format(
            format_args!(
                "Unable to toggle {0} privilege. {1}",
                caplist,
                CAPABILITIES_ERROR,
            ),
        )
    })
}
fn getopt<S, I>(s: I) -> SrResult<Cli>
where
    I: IntoIterator<Item = S>,
    S: AsRef<str>,
{
    let mut args = Cli::default();
    let mut iter = s.into_iter().skip(1);
    let mut role = None;
    let mut task = None;
    let mut workdir = None;
    let mut user: Option<SUserType> = None;
    let mut group: Option<SGroups> = None;
    let mut env = None;
    while let Some(arg) = iter.next() {
        match arg.as_ref() {
            "-u" | "--user" => {
                user = iter.next().map(|s| escape_parser_string(s).as_str().into());
            }
            "-g" | "--group" => {
                group = iter
                    .next()
                    .map(|s| {
                        SGroups::Multiple(
                            s
                                .as_ref()
                                .split(',')
                                .map(std::convert::Into::into)
                                .collect::<Vec<SGroupType>>(),
                        )
                    });
            }
            "-S" | "--stdin" => {
                args.stdin = true;
            }
            "-r" | "--role" => {
                role = iter.next().map(|s| escape_parser_string(s));
            }
            "-t" | "--task" => {
                task = iter.next().map(|s| escape_parser_string(s));
            }
            "-E" | "--preserve-env" => {
                env.replace(EnvBehavior::Keep);
            }
            "-D" | "--chdir" => {
                workdir = iter.next().map(|s| escape_parser_string(s));
            }
            "-K" | "--remove-timestamp" => {
                args.del_ts = true;
            }
            "-p" | "--prompt" => {
                args.prompt = Some(
                    iter
                        .next()
                        .map(|s| escape_parser_string(s))
                        .expect("Missing prompt for -p option"),
                );
            }
            "-i" | "--info" => {
                args.info = true;
            }
            "-h" | "--help" => {
                args.help = true;
            }
            "-v" | "--version" => {
                {
                    ::std::io::_print(format_args!("dosr: version {0}\n", "4.0.0"));
                };
                std::process::exit(0);
            }
            _ => {
                if arg.as_ref().starts_with('-') {
                    {
                        {
                            let lvl = ::log::Level::Error;
                            if lvl <= ::log::STATIC_MAX_LEVEL
                                && lvl <= ::log::max_level()
                            {
                                ::log::__private_api::log(
                                    { ::log::__private_api::GlobalLogger },
                                    format_args!("Unknown option: {0}", arg.as_ref()),
                                    lvl,
                                    &("dosr", "dosr", ::log::__private_api::loc()),
                                    (),
                                );
                            }
                        }
                    };
                    return Err(SrError::InvalidAgruments);
                }
                args.cmd_path = arg.as_ref().into();
                break;
            }
        }
    }
    args.opt_filter = Some(
        FilterMatcher::builder()
            .maybe_role(role)
            .maybe_task(task)
            .maybe_workdir(workdir)
            .maybe_env_behavior(env)
            .maybe_user(user)
            .map_err(|e| {
                {
                    {
                        let lvl = ::log::Level::Error;
                        if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                            ::log::__private_api::log(
                                { ::log::__private_api::GlobalLogger },
                                format_args!("Error parsing user: {0}", e),
                                lvl,
                                &("dosr", "dosr", ::log::__private_api::loc()),
                                (),
                            );
                        }
                    }
                };
                SrError::InvalidAgruments
            })?
            .maybe_group(group)
            .map_err(|e| {
                {
                    {
                        let lvl = ::log::Level::Error;
                        if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                            ::log::__private_api::log(
                                { ::log::__private_api::GlobalLogger },
                                format_args!("Error parsing group: {0}", e),
                                lvl,
                                &("dosr", "dosr", ::log::__private_api::loc()),
                                (),
                            );
                        }
                    }
                };
                SrError::InvalidAgruments
            })?
            .build(),
    );
    for arg in iter {
        args.cmd_args.push(escape_parser_string(arg));
    }
    Ok(args)
}
fn main() {
    if let Err(e) = subsribe("sr") {
        {
            ::std::io::_eprint(
                format_args!("dosr: Failed to initialize logging: {0}\n", e),
            );
        };
        std::process::exit(1);
    }
    if let Err(e) = main_inner() {
        {
            ::std::io::_eprint(format_args!("dosr: {0}\n", e));
        };
        if e == SrError::InsufficientPrivileges {
            {
                {
                    let lvl = ::log::Level::Error;
                    if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                        ::log::__private_api::log(
                            { ::log::__private_api::GlobalLogger },
                            format_args!(
                                "Insufficient privileges to run sr. {0}",
                                CAPABILITIES_ERROR,
                            ),
                            lvl,
                            &("dosr", "dosr", ::log::__private_api::loc()),
                            (),
                        );
                    }
                }
            };
        } else if e == SrError::AuthenticationFailed {
            {
                {
                    let lvl = ::log::Level::Error;
                    if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                        ::log::__private_api::log(
                            { ::log::__private_api::GlobalLogger },
                            format_args!(
                                "Authentication failed for user \'{0}\', when trying running \'\'\'{1}\'\'\'",
                                User::from_uid(Uid::current())
                                    .and_then(|u| {
                                        u.map(|u| u.name).ok_or(nix::errno::Errno::EAGAIN)
                                    })
                                    .unwrap_or_else(|_| Uid::current().to_string()),
                                std::env::args().skip(1).collect::<Vec<_>>().join(" "),
                            ),
                            lvl,
                            &("dosr", "dosr", ::log::__private_api::loc()),
                            (),
                        );
                    }
                }
            };
            {
                ::std::io::_eprint(format_args!("This incident is reported.\n"));
            };
        } else {
            {
                {
                    let lvl = ::log::Level::Error;
                    if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                        ::log::__private_api::log(
                            { ::log::__private_api::GlobalLogger },
                            format_args!(
                                "User \'{0}\' got a \'{1}\' when trying running \'\'\'{2}\'\'\'",
                                User::from_uid(Uid::current())
                                    .and_then(|u| {
                                        u.map(|u| u.name).ok_or(nix::errno::Errno::EAGAIN)
                                    })
                                    .unwrap_or_else(|_| Uid::current().to_string()),
                                e,
                                std::env::args().skip(1).collect::<Vec<_>>().join(" "),
                            ),
                            lvl,
                            &("dosr", "dosr", ::log::__private_api::loc()),
                            (),
                        );
                    }
                }
            };
        }
        std::process::exit(1);
    }
}
#[allow(clippy::too_many_lines)]
fn main_inner() -> SrResult<()> {
    use std::env;
    use crate::{
        ROOTASROLE, finder::api::{Api, register_plugins},
        pam::start_session,
    };
    use finder::find_best_exec_settings;
    {
        {
            let lvl = ::log::Level::Debug;
            if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                ::log::__private_api::log(
                    { ::log::__private_api::GlobalLogger },
                    format_args!(
                        "Started with capabilities: {0:?}",
                        CapState::get_current()?,
                    ),
                    lvl,
                    &("dosr", "dosr", ::log::__private_api::loc()),
                    (),
                );
            }
        }
    };
    drop_effective()?;
    let args = std::env::args();
    if args.len() < 2 {
        {
            ::std::io::_print(format_args!("{0}\n", USAGE));
        };
        return Ok(());
    }
    let args = getopt(args)?;
    if args.help {
        {
            ::std::io::_print(format_args!("{0}\n", USAGE));
        };
        return Ok(());
    }
    let user = make_cred().map_err(|_| SrError::SystemError)?;
    if args.del_ts {
        {
            timeout::clear_cookies(&user)
                .map_err(|e| {
                    {
                        {
                            let lvl = ::log::Level::Error;
                            if lvl <= ::log::STATIC_MAX_LEVEL
                                && lvl <= ::log::max_level()
                            {
                                ::log::__private_api::log(
                                    { ::log::__private_api::GlobalLogger },
                                    format_args!("Failed to clear timestamp cookies: {0}", e),
                                    lvl,
                                    &("dosr", "dosr", ::log::__private_api::loc()),
                                    (),
                                );
                            }
                        }
                    };
                    SrError::InsufficientPrivileges
                })?;
            if args.cmd_path.as_os_str().is_empty() {
                return Ok(());
            }
        }
    }
    register_plugins();
    let execcfg = find_best_exec_settings(
        &args,
        &user,
        &ROOTASROLE.to_string(),
        env::vars(),
        env::var("PATH").unwrap_or_default().split(':').collect::<Vec<_>>().as_slice(),
    )?;
    {
        {
            let lvl = ::log::Level::Debug;
            if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                ::log::__private_api::log(
                    { ::log::__private_api::GlobalLogger },
                    format_args!("Best exec settings: {0:?}", execcfg),
                    lvl,
                    &("dosr", "dosr", ::log::__private_api::loc()),
                    (),
                );
            }
        }
    };
    let _session = start_session(&execcfg.auth, &execcfg.timeout, &user, &args)?;
    if !execcfg.score.fully_matching() {
        {
            ::std::io::_print(
                format_args!(
                    "You are not allowed to execute this command, this incident will be reported.\n",
                ),
            );
        };
        {
            {
                let lvl = ::log::Level::Error;
                if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                    ::log::__private_api::log(
                        { ::log::__private_api::GlobalLogger },
                        format_args!(
                            "User {0} tried to execute command : {1} {2:?} without the permission.",
                            &user.user.name,
                            args.cmd_path.display(),
                            args.cmd_args,
                        ),
                        lvl,
                        &("dosr", "dosr", ::log::__private_api::loc()),
                        (),
                    );
                }
            }
        };
        std::process::exit(1);
    }
    if args.info {
        use capctl::CapSet;
        {
            ::std::io::_print(
                format_args!(
                    "Role: {0}\n",
                    if execcfg.role.is_empty() { "None" } else { &execcfg.role },
                ),
            );
        };
        {
            ::std::io::_print(
                format_args!("Task: {0}\n", execcfg.task.as_ref().map_or("None", |v| v)),
            );
        };
        {
            ::std::io::_print(
                format_args!(
                    "Execute as user: {0}",
                    if let Some(u) = execcfg.cred.setuid {
                        ::alloc::__export::must_use({
                            ::alloc::fmt::format(
                                format_args!("{0} ({1})", u.name, u.uid),
                            )
                        })
                    } else {
                        "Your current user".to_string()
                    },
                ),
            );
        };
        if let Some(gids) = execcfg.cred.setgroups.as_ref() {
            {
                ::std::io::_print(format_args!(" and group(s): "));
            };
            let groups = gids
                .iter()
                .map(|g| ::alloc::__export::must_use({
                    ::alloc::fmt::format(format_args!("{0} ({1})", g.name, g.gid))
                }))
                .collect::<Vec<_>>()
                .join(", ");
            {
                ::std::io::_print(format_args!("{0}\n", groups));
            };
        } else {
            {
                ::std::io::_print(format_args!(" your current group(s)\n"));
            };
        }
        {
            ::std::io::_print(
                format_args!(
                    "With capabilities: {0}\n",
                    execcfg
                        .cred
                        .caps
                        .map_or_else(
                            || "None".to_string(),
                            |caps| {
                                if caps == !CapSet::empty() {
                                    "All capabilities".to_string()
                                } else {
                                    caps.into_iter()
                                        .fold(
                                            String::new(),
                                            |acc, cap| acc + &cap.to_string() + " ",
                                        )
                                        .trim_end()
                                        .to_string()
                                }
                            },
                        ),
                ),
            );
        };
        {
            ::std::io::_print(
                format_args!(
                    "Command: {0} {1:?}\n",
                    execcfg.final_path.display(),
                    args.cmd_args,
                ),
            );
        };
        std::process::exit(0);
    }
    let mut command_builder = Command::new(&execcfg.final_path);
    configure_pre_exec(
        execcfg.umask.0,
        execcfg.cred.clone(),
        execcfg.bounding,
        execcfg.root.is_user(),
    );
    {
        {
            let lvl = ::log::Level::Debug;
            if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                ::log::__private_api::log(
                    { ::log::__private_api::GlobalLogger },
                    format_args!("setuid : {0:?}", execcfg.cred.setuid),
                    lvl,
                    &("dosr", "dosr", ::log::__private_api::loc()),
                    (),
                );
            }
        }
    };
    let cargs = args.cmd_args.clone();
    let cfinal_path = execcfg.final_path.clone();
    let cfinal_env = execcfg.clone().env;
    Api::notify(finder::api::ApiEvent::PreExec(&args, &execcfg))?;
    if let Some(workdir) = args.opt_filter.as_ref().and_then(|f| f.workdir.as_ref()) {
        command_builder.current_dir(workdir);
    } else if let Some(workdir) = execcfg.workdir.as_ref() {
        command_builder.current_dir(workdir);
    }
    command_builder.args(cargs.iter());
    command_builder.env_clear();
    command_builder.envs(cfinal_env);
    let logger = rar_exec::runner::SimpleFileLogger::new("/tmp/dosr-session.log")
        .ok()
        .map(|l| Box::new(l) as Box<dyn rar_exec::pipe::IoLogger>);
    {
        {
            let lvl = ::log::Level::Debug;
            if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                ::log::__private_api::log(
                    { ::log::__private_api::GlobalLogger },
                    format_args!(
                        "Command (via Runner): {0} {1:?}",
                        cfinal_path.display(),
                        cargs.join(" "),
                    ),
                    lvl,
                    &("dosr", "dosr", ::log::__private_api::loc()),
                    (),
                );
            }
        }
    };
    let status = match rar_exec::runner::run(
        command_builder,
        PRE_EXEC_ORCHESTRATOR,
        logger,
    ) {
        Ok(status) => status,
        Err(e) => {
            {
                {
                    let lvl = ::log::Level::Error;
                    if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                        ::log::__private_api::log(
                            { ::log::__private_api::GlobalLogger },
                            format_args!("{0}", e),
                            lvl,
                            &("dosr", "dosr", ::log::__private_api::loc()),
                            (),
                        );
                    }
                }
            };
            {
                ::std::io::_eprint(
                    format_args!("dosr: {0} : {1}\n", cfinal_path.display(), e),
                );
            };
            std::process::exit(1);
        }
    };
    std::process::exit(status.code().unwrap_or(1));
}
fn make_cred() -> std::io::Result<Cred> {
    Ok(
        Cred::builder()
            .user()?
            .groups()?
            .curdir()?
            .maybe_tty(
                stat::fstat(stdout())
                    .ok()
                    .and_then(|s| {
                        if isatty(stdout()).ok().unwrap_or(false) {
                            Some(s.st_rdev)
                        } else {
                            None
                        }
                    }),
            )
            .build(),
    )
}
fn set_capabilities(cred: &CredOwnedData, bounding: SBounding) -> SrResult<()> {
    let caps = cred.caps.unwrap_or_default();
    let sbounding = capctl::bounding::probe();
    if sbounding & caps != caps {
        {
            {
                let lvl = ::log::Level::Error;
                if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                    ::log::__private_api::log(
                        { ::log::__private_api::GlobalLogger },
                        format_args!(
                            "Unable to setup the execution environment: There are more capabilities in this task than the current bounding set! You may are in a container or already in a RootAsRole session.",
                        ),
                        lvl,
                        &("dosr", "dosr", ::log::__private_api::loc()),
                        (),
                    );
                }
            }
        };
        return Err(SrError::InsufficientPrivileges);
    }
    initialize_capabilities(&[Cap::SETPCAP])
        .inspect_err(|_| {
            {
                let lvl = ::log::Level::Error;
                if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                    ::log::__private_api::log(
                        { ::log::__private_api::GlobalLogger },
                        format_args!("{0}", cap_effective_error("setpcap")),
                        lvl,
                        &("dosr", "dosr", ::log::__private_api::loc()),
                        (),
                    );
                }
            }
        })?;
    let mut capstate = CapState::empty();
    if bounding.is_strict() {
        for cap in (!caps).iter() {
            capctl::bounding::drop(cap).expect("Failed to set bounding cap");
        }
    }
    capstate.effective.clear();
    capstate.permitted = caps;
    capstate.inheritable = caps;
    {
        {
            let lvl = ::log::Level::Debug;
            if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                ::log::__private_api::log(
                    { ::log::__private_api::GlobalLogger },
                    format_args!("caps : {0:?}", caps),
                    lvl,
                    &("dosr", "dosr", ::log::__private_api::loc()),
                    (),
                );
            }
        }
    };
    capstate.set_current().expect("Failed to set current cap");
    for cap in caps.iter() {
        capctl::ambient::raise(cap).expect("Failed to set ambiant cap");
    }
    Ok(())
}
fn setuid_setgid(cred: &CredOwnedData) -> SrResult<()> {
    let gid = cred
        .setgroups
        .as_ref()
        .and_then(|g| g.first().cloned())
        .map(|g| g.gid.as_raw());
    with_privileges(
            &[Cap::SETUID, Cap::SETGID],
            || {
                capctl::cap_set_ids(
                    cred.setuid.as_ref().map(|u| u.uid.as_raw()),
                    gid,
                    cred
                        .setgroups
                        .as_ref()
                        .map(|g| g.iter().map(|g| g.gid.as_raw()).collect::<Vec<_>>())
                        .as_deref(),
                )?;
                Ok(())
            },
        )
        .map_err(|e| {
            {
                {
                    let lvl = ::log::Level::Error;
                    if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                        ::log::__private_api::log(
                            { ::log::__private_api::GlobalLogger },
                            format_args!("{0}", cap_effective_error("setuid/setgid")),
                            lvl,
                            &("dosr", "dosr", ::log::__private_api::loc()),
                            (),
                        );
                    }
                }
            };
            e.into()
        })
}
fn close_restrictive_fds() -> io::Result<()> {
    {
        {
            let lvl = ::log::Level::Debug;
            if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                ::log::__private_api::log(
                    { ::log::__private_api::GlobalLogger },
                    format_args!("Closing restrictive FDs"),
                    lvl,
                    &("dosr", "dosr", ::log::__private_api::loc()),
                    (),
                );
            }
        }
    };
    let mut fds = Vec::new();
    let read_dir = std::fs::read_dir("/proc/self/fd")?;
    let mut error = false;
    for entry in read_dir.flatten() {
        if let Ok(fd) = entry.file_name().to_string_lossy().parse::<i32>() {
            if fd > 2 {
                fds.push(fd);
            } else {
                {
                    {
                        let lvl = ::log::Level::Error;
                        if lvl <= ::log::STATIC_MAX_LEVEL && lvl <= ::log::max_level() {
                            ::log::__private_api::log(
                                { ::log::__private_api::GlobalLogger },
                                format_args!("Failed to read fd entry: {0:?}", entry),
                                lvl,
                                &("dosr", "dosr", ::log::__private_api::loc()),
                                (),
                            );
                        }
                    }
                };
                error = true;
            }
        }
    }
    for fd in fds {
        let _ = nix::unistd::close(fd);
    }
    if error { Err(io::Error::other("Failed to read some fd entries")) } else { Ok(()) }
}
